// HTML escape helper (XSS protection)
const esc = (s = '') => String(s)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;')
  .replaceAll("'", '&#39;');

const data = $input.first().json;

const customerName = data['Full name'] || 'Customer';
const customerEmail = data['Email'] || '';
const request = data['What do you need'] || '';
const budget = data['Estimated budget'] || 'Not specified';

const quoteNumber = 'QTE-' + new Date().toISOString().slice(0, 10).replaceAll('-', '') + '-' + String(Date.now()).slice(-4);
const validityDays = Number(data.quoteValidityDays) || 30;
const validUntil = new Date(Date.now() + validityDays * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

const html = `<!DOCTYPE html>
<html>
<head>
<style>
  body { font-family: Arial, sans-serif; padding: 40px; color: #1e293b; }
  h1 { margin: 0 0 4px 0; } h2 { color: #64748b; margin: 0 0 24px 0; font-weight: 600; }
  .meta p { margin: 4px 0; }
  .request { margin: 24px 0; padding: 16px; background: #f8fafc; border-left: 3px solid #cbd5e1; white-space: pre-wrap; }
  .note { color: #64748b; font-size: 14px; margin-top: 32px; }
</style>
</head>
<body>
  <h1>${esc(data.companyName || 'Your Company Inc.')}</h1>
  <h2>QUOTE</h2>
  <div class="meta">
    <p><strong>Quote #:</strong> ${quoteNumber}</p>
    <p><strong>Date:</strong> ${new Date().toISOString().slice(0, 10)}</p>
    <p><strong>Valid until:</strong> ${validUntil}</p>
    <p><strong>Prepared for:</strong> ${esc(customerName)} (${esc(customerEmail)})</p>
    <p><strong>Estimated budget:</strong> ${esc(budget)}</p>
  </div>
  <h3>Your request</h3>
  <div class="request">${esc(request)}</div>
  <p class="note">${esc(data.hourlyRateNote || '')}</p>
</body>
</html>`;

return [{
  json: {
    html,
    quoteNumber,
    customerName,
    customerEmail,
    validUntil,
    quoteFilename: quoteNumber + '.pdf'
  }
}];
